
"use client";
import { useSpring, animated } from "@react-spring/web";
import React from "react";
import Link from "next/link";
import { ArrowRight } from "lucide-react";

 const HomeCard = ({ title, description, link, gradient }: {
  title: string;
  description: string;
  link: string;
  gradient: string;
}) => {
  const [hovered,setHovered] = React.useState(false);
  const arrowSpring =useSpring({
    from:{ transform:'translateX(-100%)', opacity: 0},
    to: {transform: hovered ? 'translateX(0%)' : 'transformX(-100%)', opacity: hovered ? 1: 0},
    config:{ tension: 300, friction:20},

 });

 const cardSpring= useSpring({
  transform: hovered ? 'translateY(-12px) scale(1.04)' :'translateY(0px) scale(1)',
  boxShadow: hovered
  ? '0 25px 50px -12px  rgba(0, 0, 0, 0.25)'
  : '0 4px  6px -1px rgba(0, 0, 0, 0.1)',
  config: {tension:300,friction: 20},
 });

return (
  <Link href={link}>
    <animated.div 
    className={`group-relative overflow-hidden rounded-2xl bg-white shadow-lg cursor-pointer h-64 transition-all duration-300 ${gradient}`}
    style={cardSpring}
    onMouseEnter={() => setHovered(true)}
    onMouseLeave={() => setHovered(false)} 
    >
      <div className="relative z-10 p-8 h-full flex flex-col justify-between text-white">
          <div>
            <h2 className="text-3xl font-bold mb-3">{title}</h2>
            <p className="text-white/90 text-lg leading-relaxed">{description}</p>
          </div>

    <animated.div style={arrowSpring} className=" flex items-center gap-4 font-bold text-xl mt-6">
        <span> discover now</span>
        <ArrowRight className="w-9 h-9 group-hover:translate-x-2 transition-transform" />
      </animated.div>
      </div>
      <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transpartent opacity-0 group-hover:opacity-100 transform -skew-x-12 translate-x-[-200%] group-hover:translate-x-[200%] transition-transform duration-1000 pointer-events-none" />
    </animated.div>
  </Link>
 );
};

export default HomeCard;